import { Component, OnDestroy, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Subject, combineLatest, startWith, takeUntil } from 'rxjs';
import { StockCategory, StockColor, StockItem, StockSerie } from '../../models/stock-item';
import { StockMovementType } from '../../models/stock-movement';
import { StockStoreService } from '../../services/stock-store.service';

interface StockGroup {
  category: StockCategory;
  serie: StockSerie;
  items: StockItem[];
}

interface MovementModalState {
  open: boolean;
  item: StockItem | null;
  type: StockMovementType;
  availableColors: StockColor[];
}

@Component({
  selector: 'app-stock',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './stock.component.html',
  styleUrls: ['./stock.component.css']
})
export class StockComponent implements OnInit, OnDestroy {
  private readonly destroy$ = new Subject<void>();

  filters = this.fb.group({
    search: [''],
    serie: ['all'],
    category: ['all'],
    color: ['all']
  });

  movementForm = this.fb.group({
    color: ['blanc' as StockColor],
    delta: [1, [Validators.required]],
    adjustSign: ['+' as '+' | '-'],
    reason: ['', Validators.required],
    actor: ['', Validators.required]
  });

  groupedItems: StockGroup[] = [];
  totalItems = 0;
  alertItems = 0;

  modal: MovementModalState = {
    open: false,
    item: null,
    type: 'IN',
    availableColors: ['blanc', 'gris', 'noir']
  };

  constructor(private fb: FormBuilder, private store: StockStoreService) {}

  ngOnInit(): void {
    void this.store.load();

    combineLatest([
      this.store.items$,
      this.filters.valueChanges.pipe(startWith(this.filters.getRawValue()))
    ])
      .pipe(takeUntil(this.destroy$))
      .subscribe(([items, filters]) => {
        const search = (filters.search ?? '').trim().toLowerCase();
        const serie = filters.serie ?? 'all';
        const category = filters.category ?? 'all';
        const color = filters.color ?? 'all';

        const filtered = items.filter((item) => {
          const matchesSearch = !search ||
            item.reference.toLowerCase().includes(search) ||
            item.label.toLowerCase().includes(search);
          const matchesSerie = serie === 'all' || item.serie === serie;
          const matchesCategory = category === 'all' || item.category === category;
          const matchesColor = color === 'all' || this.hasColor(item, color as StockColor);
          return matchesSearch && matchesSerie && matchesCategory && matchesColor;
        });

        this.totalItems = filtered.length;
        this.alertItems = filtered.filter((item) => this.isLowStock(item)).length;
        this.groupedItems = this.groupByCategory(filtered);
      });
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  trackById(index: number, item: StockItem): string {
    return item.id;
  }

  openMove(item: StockItem, type: StockMovementType): void {
    const colors = this.getAvailableColors(item);
    this.modal = {
      open: true,
      item,
      type,
      availableColors: colors
    };

    this.movementForm.reset({
      color: colors[0] ?? 'noir',
      delta: 1,
      adjustSign: '+',
      reason: '',
      actor: ''
    });
  }

  closeModal(): void {
    this.modal = {
      open: false,
      item: null,
      type: 'IN',
      availableColors: ['blanc', 'gris', 'noir']
    };
  }

  async submitMovement(): Promise<void> {
    if (!this.modal.item) return;
    if (this.movementForm.invalid) {
      this.movementForm.markAllAsTouched();
      return;
    }

    const raw = this.movementForm.getRawValue();
    const delta = Math.abs(Number(raw.delta) || 0);
    if (delta === 0) return;

    const signedDelta = this.modal.type === 'ADJUST'
      ? (raw.adjustSign === '-' ? -delta : delta)
      : delta;

    await this.store.moveStock({
      itemId: this.modal.item.id,
      color: raw.color as StockColor,
      type: this.modal.type,
      delta: signedDelta,
      reason: raw.reason ?? '',
      actor: raw.actor ?? ''
    });

    this.closeModal();
  }

  getQuantity(item: StockItem, color: StockColor): number {
    return Number(item.quantities[color] ?? 0) || 0;
  }

  getAvailableColors(item: StockItem): StockColor[] {
    const colors = Object.keys(item.quantities) as StockColor[];
    const order: StockColor[] = ['blanc', 'gris', 'noir'];
    const sorted = colors.sort((a, b) => order.indexOf(a) - order.indexOf(b));
    return sorted.length > 0 ? sorted : ['noir'];
  }

  isLowStock(item: StockItem): boolean {
    const colors = this.getAvailableColors(item);
    return colors.some((color) => this.getQuantity(item, color) <= item.lowStockThreshold);
  }

  private hasColor(item: StockItem, color: StockColor): boolean {
    return Object.prototype.hasOwnProperty.call(item.quantities, color);
  }

  private groupByCategory(items: StockItem[]): StockGroup[] {
    const map = new Map<string, StockItem[]>();
    items.forEach((item) => {
      const key = `${item.serie}|${item.category}`;
      const group = map.get(key) ?? [];
      group.push(item);
      map.set(key, group);
    });

    return Array.from(map.entries()).map(([key, groupItems]) => {
      const [serie, category] = key.split('|') as [StockSerie, StockCategory];
      return {
        serie,
        category,
        items: groupItems
      };
    });
  }
}
<section class="panel">
  <div class="panel-header">
    <div>
      <h1>Gestion Stock</h1>
      <p>Suivi des niveaux par couleur avec historique complet.</p>
    </div>
  </div>

  <section class="card">
    <div class="filters" [formGroup]="filters">
      <label class="field">
        <span>Recherche</span>
        <input class="input" type="search" formControlName="search" placeholder="Reference ou nom">
      </label>
      <label class="field">
        <span>Categorie</span>
        <select class="input" formControlName="category">
          <option value="all">Toutes</option>
          <option value="profil">Profils</option>
          <option value="accessoire">Accessoires</option>
          <option value="joint">Joints</option>
        </select>
      </label>
      <label class="field">
        <span>Couleur</span>
        <select class="input" formControlName="color">
          <option value="all">Toutes</option>
          <option value="blanc">Blanc</option>
          <option value="gris">Gris</option>
          <option value="noir">Noir</option>
        </select>
      </label>
    </div>

    <div class="summary">
      <div>
        <span>Total articles</span>
        <strong>{{ totalItems }}</strong>
      </div>
      <div class="alert">
        <span>Articles en alerte</span>
        <strong>{{ alertItems }}</strong>
      </div>
    </div>
  </section>

  <section class="stock-groups">
    <div class="stock-group" *ngFor="let group of groupedItems">
      <div class="group-header">
        <h2>{{ group.category | titlecase }}</h2>
        <span class="tag">{{ group.items.length }} articles</span>
      </div>

      <div class="stock-grid">
        <article
          class="stock-card"
          *ngFor="let item of group.items; trackBy: trackById"
          [class.low-stock]="isLowStock(item)"
        >
          <div class="stock-image">
            <img [src]="item.imageUrl" alt="Stock item">
            <span class="badge" *ngIf="isLowStock(item)">Rupture</span>
          </div>
          <div class="stock-info">
            <div class="stock-ref">{{ item.reference }}</div>
            <div class="stock-label">{{ item.label }}</div>
          </div>

          <div class="stock-colors">
            <div class="color-row" *ngFor="let color of getAvailableColors(item)">
              <span class="color-name">{{ color }}</span>
              <span class="color-qty">{{ getQuantity(item, color) }}</span>
              <span class="color-alert" *ngIf="getQuantity(item, color) <= item.lowStockThreshold">
                Rupture proche
              </span>
            </div>
          </div>

          <div class="stock-actions">
            <button class="btn outline" type="button" (click)="openModal(item, 'IN')">Ajouter</button>
            <button class="btn ghost" type="button" (click)="openModal(item, 'OUT')">Retirer</button>
            <button class="btn danger" type="button" (click)="openModal(item, 'ADJUST')">Ajuster</button>
          </div>
        </article>
      </div>
    </div>
  </section>
</section>

<div class="modal-backdrop" *ngIf="modal.open">
  <div class="modal-card" role="dialog" aria-modal="true">
    <div class="modal-header">
      <h2>Mouvement {{ modal.type === 'IN' ? 'Ajouter' : modal.type === 'OUT' ? 'Retirer' : 'Ajuster' }}</h2>
      <button class="btn ghost" type="button" (click)="closeModal()">Fermer</button>
    </div>

    <div class="modal-body" *ngIf="modal.item as item">
      <div class="modal-item">
        <strong>{{ item.reference }}</strong>
        <span>{{ item.label }}</span>
      </div>

      <form class="modal-form" [formGroup]="movementForm">
        <label class="field" *ngIf="modal.availableColors.length > 1">
          <span>Couleur</span>
          <select class="input" formControlName="color">
            <option *ngFor="let color of modal.availableColors" [value]="color">{{ color }}</option>
          </select>
        </label>

        <label class="field" *ngIf="modal.availableColors.length === 1">
          <span>Couleur</span>
          <div class="tag">{{ modal.availableColors[0] }}</div>
        </label>

        <label class="field">
          <span>Quantite</span>
          <input
            class="input"
            type="number"
            [attr.min]="modal.type === 'ADJUST' ? null : 1"
            step="1"
            formControlName="delta"
          >
        </label>

        <label class="field">
          <span>Raison</span>
          <input class="input" type="text" formControlName="reason" placeholder="Inventaire, commande, casse...">
        </label>

        <label class="field">
          <span>Employe</span>
          <input class="input" type="text" formControlName="actor" placeholder="Nom">
        </label>
      </form>
    </div>

    <div class="modal-actions">
      <button class="btn ghost" type="button" (click)="closeModal()">Annuler</button>
      <button class="btn primary" type="button" (click)="submitMovement()">Valider</button>
    </div>
  </div>
</div>
